  ('social-worker-moex-01683', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理是組織資源以完成工作的過程，若是強調「做對的事情」係屬於管理概念中那項重要的要素？', '["資源", "活動或過程", "效率", "效能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01684', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織透過管道取得更多方案或提供更多元性的服務，以爭取更多的服務對象來降低服務的單位成 本，但卻未提供合理的服務品質而招致批評，係屬於下列那種效率與效能的組合樣態？', '["高效率、高效能", "高效率、低效能", "低效率、高效能", "低效率、低效能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01685', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '強調「只有那些最有可能發生或其影響會對組織產生最大衝擊事件，才被運用於權變性規劃的過 程」是屬於下列何項行動切入點的任務？', '["行動切入點1：擬訂計畫，並考慮情境事件", "行動切入點2：執行計畫，並正式確認情境事件", "行動切入點3：確立情境事件指標，並就每個可能的情境事件擬訂權變計畫", "行動切入點4：順利完成原始計畫或權變計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01686', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '重視組織結構對組織績效的影響，沒有適用所有情境的最佳設計，需視工作的性質及其所處環境 特性而定，此論述為何種管理觀點？', '["古典管理觀點（classical approach to management）", "權變觀點（contingency approach）", "系統觀點（system approach）", "人群關係觀點（human relationship approach）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01687', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某非營利組織的管理階層以優渥薪資與福利吸引社工系畢業生加入，並以績效獎金獎勵工作表現 優異者，此管理理念是受到何種管理理論的影響？', '["Z理論", "X理論", "Y理論", "S理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01688', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Z理論常見於日本的組織管理風格，下列何者為其特性？①員工不輕易跳槽  ②升遷快速  ③集', '["個人責任  ⑤重視員工訓練  ⑥管理者關心員工的福利  ⑦重視個人績效與生產力", "", "", "⑥⑦"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01689', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '強調員工若是快樂，工作就會有效率，係屬於下列何種理論？', '["行政管理理論", "科學管理理論", "人群關係理論", "科層管理理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01690', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '1910年代Frederick W. Taylor認為提供工作誘因來提升生產力，因為員工往往是懶惰的、無動力 的，分析工作內容，論件計酬是較好的付薪方式。上述觀點為何種管理學派？', '["科學管理理論", "人群關係理論", "科層管理理論", "行政管理理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
